// Create your variables here
var gameState = "start";
var Health;
Health = 100;
var Score;
Score = 0;
playSound("https://youtu.be/XqZsoesa55w", true);


function draw() {
  if (gameState == "start") {
    background("lightblue");
    fill("black");
    textSize(20);
    text("Mama Shark on the Go", 100, 80);

    textSize(14);
    text("HOW TO PLAY:", 140, 130);
    text("Use UP,DOWN,RIGHT,AND LEFT keys to move.", 50, 160);
    text("Avoid shells, seaweed, and urchins.", 80, 180);
    text("Don't let Mama Shark eat you!", 95, 200);

    text("Press SPACE to start", 110, 250);
    if (keyWentDown("space")) {
      gameState = "play";
    }

  }
  if (gameState == "play") {
    if (fish.isTouching(shell)) {
      Health = Health - 1;
    }
    if (fish.isTouching(urchin)) {
      Health = Health - 1;
    }
    if (fish.isTouching(seaweed)) {
      Health = Health - 1;
    }
    if (fish.isTouching(coin)) {
      Score = Score + 1;
    }
      //Text for Health and score
    obstacles();
    movement();
    score();
    drawSprites();
    fill("black");
    textSize(20);
    text("Score:" + Score, 20, 50);
    fill("black");
    textSize(20);
    text("Health:" + Health, 20, 30);
    if (Health <= 0) {
    background("black");
    fill("red");
    textSize(50);
    text("YOU LOSE", 75, 200);
    }
    //Functions
  }
}
// Create your sprites here
//Sprites
var ocean = createSprite(200, 200);
ocean.setAnimation("background_underwater_17_1");
var fish = createSprite(150, 200);
fish.setAnimation("Screenshot 2026-03-05 140237.png_1");
fish.scale = .3;
var mshark = createSprite(50, 200);
mshark.setAnimation("Screenshot 2026-03-04 151556.png_1");
mshark.scale = .4;
var shell = createSprite(400, 200);
shell.setAnimation("shell_09_1");
shell.scale = 0.2;
shell.velocityX = -3;
var seaweed = createSprite(400, 200);
seaweed.setAnimation("underseadeco_34_1");
seaweed.scale = 0.2;
seaweed.velocityX = -3;
var urchin = createSprite(400, 200);
urchin.setAnimation("urchin_1");
urchin.scale = 0.2;
urchin.velocityX = -3;
var coin = createSprite(200, 200);
coin.setAnimation("coin_gold_1");
coin.velocityX = -3;
coin.scale = 0.5;

World.frameRate = 100;


// Create your functions here
function obstacles() {
  if (urchin.x < 0) {
    urchin.x = 400;
    urchin.y = randomNumber(0, 400);
  }
  if (seaweed.x < 0) {
    seaweed.x = 400;
    seaweed.y = randomNumber(0, 400);
  }
  if (shell.x < 0) {
    shell.x = 400;
    shell.y = randomNumber(0, 400);

  }
  if (coin.x < 0) {
    coin.x = 400;
    coin.y = randomNumber(0, 400);
  }
  if (fish.isTouching(mshark)) {
    fish.bounceOff(mshark);
    fish.collide(mshark);
  }
}
function movement() {
  //Stopping movement when no keys are pushed
  if (keyWentUp("up")) {
    fish.velocityY = 0;
  }
  if (keyWentUp("down")) {
    fish.velocityY = 0;
  }
  if (keyWentUp("left")) {
    fish.velocityX = 0;
  }
  if (keyWentUp("right")) {
    fish.velocityX = 0;
  }
  //Actual movement
  if (keyWentDown("down")) {
    fish.velocityY = 4;
  }
  if (keyWentDown("up")) {
    fish.velocityY = -4;
  }
  if (keyWentDown("left")) {
    fish.velocityX = -4;
  }
  if (keyWentDown("right")) {
    fish.velocityX = 4;
  }
}
function score() {
  if (Score >= 150) {
    background("white");
    fill("blue");
    textSize(50);
    text("YOU WON!", 75, 200);
  }
}
